item.command:
$stamp = Get-Date -Format "yyyyMMdd_HHmmss";
$zip = "C:\Users\mrbla\backups\blarai_oog_$stamp.zip";
$paths = @(
  "C:\Users\mrbla\BlarAI\tools\vikunja",
  "C:\Users\mrbla\BlarAI\tools\vikunja_mcp\bridge",
  "C:\Users\mrbla\BlarAI\scheduled",
  "C:\Users\mrbla\BlarAI\.mcp.json",
  "C:\Users\mrbla\BlarAI\.vscode\mcp.json",
  "C:\Users\mrbla\BlarAI\.vscode\tasks.json",
  "$env:APPDATA\Claude\claude_desktop_config.json"
) | Where-Object { Test-Path $_ };
Compress-Archive -Path $paths -DestinationPath $zip -Force;
Write-Host "OOG backup: $zip"

New-Item -ItemType Directory -Path "C:\Users\mrbla\backups\scheduled_tasks_export" -Force | Out-Null;
Get-ScheduledTask -TaskPath '\BlarAI\' | ForEach-Object {
  $name = $_.TaskName;
  Export-ScheduledTask -TaskName $name -TaskPath $_.TaskPath |
    Out-File "C:\Users\mrbla\backups\scheduled_tasks_export\$name.xml" -Encoding UTF8
}

item.verify:
# Disable-ScheduledTask returns before the task scheduler service refreshes its in-memory state.
# Brief sleep prevents a false-positive where a freshly-disabled task still reports its old State.
Start-Sleep -Seconds 2;
Get-ScheduledTask -TaskPath '\BlarAI\' | Where-Object { $_.State -ne 'Disabled' }

item.command:
$manifest = "C:\Users\mrbla\backups\pre_extract_manifest.txt";
"Platform separation pre-flight manifest - $(Get-Date -Format o)" | Out-File $manifest;
Get-ChildItem C:\Users\mrbla\backups\*.bundle, C:\Users\mrbla\backups\blarai_oog_*.zip |
  ForEach-Object { "$((Get-FileHash $_.FullName -Algorithm SHA256).Hash)  $($_.Name)" | Out-File $manifest -Append }
